suspend fun loadUser(): User {
    delay(100)
    return api.getUser()
}

fun loadProfile() {
    viewModelScope.launch {
        _uiState.update { it.copy(isLoading = true) }
        try {
            val profile = repository.getProfile()
            _uiState.update { it.copy(isLoading = false, profile = profile) }
        } catch (cancelled: CancellationException) {
            throw cancelled
        } catch (error: Throwable) {
            _uiState.update { it.copy(isLoading = false, error = error) }
        }
    }
}

class DraftRepository(
    private val dao: DraftDao,
    private val io: CoroutineDispatcher
) {
    suspend fun save(draft: Draft) = withContext(io) {
        dao.upsert(draft)
    }
}

private var loadJob: Job? = null

fun load(jobId: String) {
    loadJob?.cancel()
    loadJob = viewModelScope.launch {
        _uiState.value = JobUiState.Loading(jobId)
        try {
            val job = repository.getJob(jobId)
            ensureActive()
            _uiState.value = JobUiState.Content(job)
        } catch (cancelled: CancellationException) {
            throw cancelled
        } catch (error: Throwable) {
            _uiState.value = JobUiState.Error(jobId, error)
        }
    }
}

try { repository.load() }
catch (cancelled: CancellationException) { throw cancelled }
catch (error: Throwable) { emit(Fallback) }
